// Valida os dados recebidos do front-end antes de gravar no Firestore.
// Campos obrigatórios definidos pelo schema da coleção `briefings`
// (ver services/briefings.ts e docs/integracoes/n8n.md).
const body = $input.first().json.body || $input.first().json;

const obrigatorios = [
  "cliente",
  "telefone",
  "evento",
  "data",
  "status",
  "complexidade",
];

const erros = [];

for (const campo of obrigatorios) {
  if (!body[campo] || String(body[campo]).trim() === "") {
    erros.push(`Campo obrigatório ausente ou vazio: ${campo}`);
  }
}

const statusValidos = ["Novo", "Briefing", "Orçamento", "Aprovado", "Produção", "Finalizado"];
if (body.status && !statusValidos.includes(body.status)) {
  erros.push(`Status inválido: ${body.status}`);
}

const complexidadesValidas = ["Simples", "Média", "Alta"];
if (body.complexidade && !complexidadesValidas.includes(body.complexidade)) {
  erros.push(`Complexidade inválida: ${body.complexidade}`);
}

if (body.data && !/^\d{4}-\d{2}-\d{2}$/.test(body.data)) {
  erros.push("Campo 'data' deve estar no formato ISO AAAA-MM-DD");
}

return [
  {
    json: {
      valido: erros.length === 0,
      erros,
      dados: body,
    },
  },
];

// Converte o objeto simples recebido do front-end para o formato de
// campos tipados exigido pela API REST do Firestore (fields.{campo}.{tipo}Value).
const d = $input.first().json.dados;
const agoraISO = new Date().toISOString();

function s(valor) { return { stringValue: String(valor ?? "") }; }
function n(valor) { return { integerValue: String(Number(valor) || 0) }; }

const fields = {
  companyId: s($env.DEFAULT_COMPANY_ID || "cutefood-cwb"),
  customerId: s(d.customerId || ""),
  conversationId: s(d.conversationId || ""),
  cliente: s(d.cliente),
  telefone: s(d.telefone),
  evento: s(d.evento),
  data: s(d.data),
  tema: s(d.tema),
  sabores: s(d.sabores),
  quantidade: s(d.quantidade),
  orcamento: s(d.orcamento),
  entrega: s(d.entrega),
  referencias: n(d.referencias),
  observacoes: s(d.observacoes),
  status: s(d.status || "Novo"),
  complexidade: s(d.complexidade || "Simples"),
  avatarBg: s(d.avatarBg || "bg-stone-100"),
  avatarText: s(d.avatarText || "text-stone-600"),
  createdAt: { timestampValue: agoraISO },
  updatedAt: { timestampValue: agoraISO },
};

if (Array.isArray(d.mensagens)) {
  fields.mensagens = {
    arrayValue: {
      values: d.mensagens.map((m) => ({
        mapValue: {
          fields: {
            autor: s(m.autor),
            texto: s(m.texto),
            hora: s(m.hora),
          },
        },
      })),
    },
  };
}

return [{ json: { fields } }];

// A resposta da API REST do Firestore traz o caminho completo do documento
// em `name`, ex: projects/P/databases/(default)/documents/briefings/ABC123.
// Extraímos só o ID final para devolver ao front-end.
const nomeCompleto = $input.first().json.name || "";
const partes = nomeCompleto.split("/");
const id = partes[partes.length - 1];

return [
  {
    json: {
      success: true,
      id,
    },
  },
];

return [
  {
    json: {
      success: false,
      error: "Dados inválidos para criação do briefing.",
      erros: $input.first().json.erros,
    },
  },
];
